const watch = $('Load Aggregates').all().map(i => i.json);
const cands = $('Load Candidates').all().map(i => i.json).filter(c => c.type_id);
const wt = watch.map(w =>
  `${w.type_id} | ${w.name} | locked:${w.locked} | avg7:${w.avg7} | avg30:${w.avg30} | vol7:${w.vol7} | volat%:${w.volat_pct} | opps30:${w.opps30} | bestProfit:${w.best_profit}`
).join('\n');
const ct = cands.map(c => `${c.type_id} | ${c.name}`).join('\n') || 'нет доступных кандидатов';
return [{ json: { watchlist_table: wt, candidates_table: ct } }];

