const raw = $input.first().json.text ?? $input.first().json.output ?? '';
let decision;
try {
  decision = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (e) {
  return [{ json: { action: 'none', type_id: 0, name: '', reason: 'не удалось распарсить ответ AI' } }];
}

const watch = Object.fromEntries($('Load Aggregates').all().map(i => [i.json.type_id, i.json]));
const cands = Object.fromEntries($('Load Candidates').all().filter(i => i.json.type_id).map(i => [i.json.type_id, i.json]));

const out = [];
let removes = 0, adds = 0;
for (const r of (decision.remove ?? [])) {
  const w = watch[r.type_id];
  if (!w || w.locked || removes >= 3) continue;
  removes++;
  out.push({ json: { action: 'remove', type_id: w.type_id, name: w.name,
                     reason: String(r.reason || '').replace(/,/g, ' ').slice(0, 200) } });
}
for (const a of (decision.add ?? [])) {
  const c = cands[a.type_id];
  if (!c || adds >= 3) continue;
  adds++;
  out.push({ json: { action: 'add', type_id: c.type_id, name: c.name,
                     reason: String(a.reason || '').replace(/,/g, ' ').slice(0, 200) } });
}

if (out.length === 0) return [{ json: { action: 'none', type_id: 0, name: '', reason: '' } }];
return out;

const changes = $('Validate & Apply Rules').all().map(i => i.json).filter(c => c.action !== 'none');
const message = changes.length === 0
  ? '📋 Ревью watchlist: изменений нет.'
  : '📋 Ревью watchlist:\n' + changes.map(c =>
      `${c.action === 'add' ? '➕' : '➖'} ${c.name} (${c.type_id}) — ${c.reason}`).join('\n');
return [{ json: { message } }];
